from crewai import Agent, Crew, Process, Task
from crewai.project import CrewBase, agent, crew, task

@CrewBase
class GameBuilderCrew:
    agents_config = 'config/agents.yaml'
    tasks_config = 'config/tasks.yaml'

    @agent
    def senior_engineer_agent(self) -> Agent:
        config = self.agents_config['senior_engineer_agent']
        config['backstory'] += f"\n\nGame Design Requirements:\n{self.game_design}"
        return Agent(config=config, allow_delegation=False, verbose=True)

    @agent
    def qa_engineer_agent(self) -> Agent:
        return Agent(config=self.agents_config['qa_engineer_agent'],
                      allow_delegation=False, verbose=True)

    @task
    def write_code_task(self) -> Task:
        return Task(config=self.tasks_config['write_code_task'],
                    agent=self.senior_engineer_agent())

    @task
    def review_code_task(self) -> Task:
        return Task(config=self.tasks_config['review_code_task'],
                    agent=self.qa_engineer_agent())

    @crew
    def crew(self) -> Crew:
        return Crew(
            agents=self.agents,
            tasks=self.tasks,
            process=Process.sequential,
            verbose=True
        )

