from openai import OpenAI
from typing import Optional
import subprocess

client = OpenAI()

def run_code(code: str, test: str) -> dict:
    """Execute code against a test and return results."""
    try:
        result = subprocess.run(
            ["python", "-c", code + "\n" + test],
            capture_output=True, text=True, timeout=10
        )
        return {"success": result.returncode == 0, "stdout": result.stdout,
                "stderr": result.stderr, "returncode": result.returncode}
    except subprocess.TimeoutExpired:
        return {"success": False, "stderr": "Timeout: infinite loop?"}

def locate_bug(code: str, error: str) -> str:
    """L1: Simple bug location."""
    resp = client.chat.completions.create(
        model="gpt-4o-mini", messages=[
            {"role": "system", "content": "Locate the bug. Return only the line number."},
            {"role": "user", "content": f"Code:\n{code}\n\nError:\n{error}"}
        ])
    return resp.choices[0].message.content

def fix_bug(code: str, bug_location: str, error: str) -> str:
    """L1: Simple bug fix."""
    resp = client.chat.completions.create(
        model="gpt-4o-mini", messages=[
            {"role": "system", "content": "Fix the bug at the indicated location. Return ONLY the fixed code."},
            {"role": "user", "content": f"Code:\n{code}\nBug at: {bug_location}\nError: {error}"}
        ])
    return resp.choices[0].message.content

def get_context(code: str, error: str) -> str:
    """L2: Slice relevant code and summarize context."""
    resp = client.chat.completions.create(
        model="gpt-4o", messages=[
            {"role": "system", "content": "Analyze the code to provide debugging context. "
         "Identify related functions, data flow, and potential cross-dependencies."},
            {"role": "user", "content": f"Code:\n{code}\nError: {error}"}
        ])
    return resp.choices[0].message.content

def hierarchical_debug(code: str, test: str, max_levels: int = 3) -> str:
    """Hierarchical debugging with escalation."""
    current_code = code
    for level in range(1, max_levels + 1):
        result = run_code(current_code, test)
        if result["success"]:
            print(f"Fixed at level {level}!")
            return current_code

        error = result.get("stderr", result.get("stdout", "Unknown error"))
        print(f"Level {level} attempt. Error: {error[:100]}")

        if level == 1:
            bug_loc = locate_bug(current_code, error)
            current_code = fix_bug(current_code, bug_loc, error)
        elif level == 2:
            context = get_context(current_code, error)
            bug_loc = locate_bug(current_code, f"{error}\nContext: {context}")
            current_code = fix_bug(current_code, bug_loc, f"{error}\nContext: {context}")
        elif level == 3:
            resp = client.chat.completions.create(
                model="gpt-4o", messages=[
                    {"role": "system", "content": "This bug requires cross-file analysis. "
                 "Rewrite the entire function considering all edge cases."},
                    {"role": "user", "content": f"Code:\n{current_code}\nError: {error}\nPrevious attempts failed."}
                ])
            current_code = resp.choices[0].message.content

    print("All levels exhausted.")
    return current_code

